<script lang="ts">
  const html: string = "<h1>ThemeProvider</h1>\n\n<p>A container that applies CSS custom properties from a theme object to its children, enabling scoped visual theming without affecting layout.</p>\n\n<p>This headless component uses a <code>&lt;div&gt;</code> element with <code>display: contents</code> that flattens a nested theme object into <code>--theme-*</code> CSS custom properties on its style attribute.</p>\n\n<h2>Implementation Notes</h2>\n\n<ul>\n<li>Uses <code>&lt;div&gt;</code> element with <code>display: contents</code> to avoid affecting layout</li>\n<li>Flattens nested theme object keys into <code>--theme-*</code> CSS custom properties</li>\n<li>Merges custom theme with a base light or dark theme</li>\n<li>Nested ThemeProvider components can override parent theme values</li>\n<li>CSS custom property output: <code>{ color: { text: \"#1a1a1a\" } }</code> becomes <code>--theme-color-text: #1a1a1a</code></li>\n</ul>\n\n<h2>Props</h2>\n\n<ul>\n<li><code>theme</code>: object (required) -- theme object with key-value pairs flattened to CSS custom properties</li>\n<li><code>base</code>: \"light\" | \"dark\" (default: \"light\") -- base theme to merge with</li>\n<li><code>children</code>: slot (required) -- themed content</li>\n<li><code>...restProps</code>: Any additional HTML attributes</li>\n</ul>\n\n<h2>Usage</h2>\n\n<pre><code class=\"language-html\">&lt;ThemeProvider theme={{ color: { text: \"#1a1a1a\", background: \"#ffffff\", accent: \"#2563eb\" } }} base=\"light\"&gt;\n  &lt;Card&gt;\n    &lt;p&gt;This content uses the custom theme colors.&lt;/p&gt;\n  &lt;/Card&gt;\n&lt;/ThemeProvider&gt;</code></pre>\n\n<pre><code class=\"language-html\">&lt;ThemeProvider theme={{ color: { text: \"#f0f0f0\", background: \"#1a1a1a\" } }} base=\"dark\"&gt;\n  &lt;Panel&gt;\n    &lt;p&gt;Dark-themed content area.&lt;/p&gt;\n  &lt;/Panel&gt;\n&lt;/ThemeProvider&gt;</code></pre>\n\n<pre><code class=\"language-html\">&lt;ThemeProvider theme={{ spacing: { sm: \"0.5rem\", md: \"1rem\", lg: \"2rem\" } }}&gt;\n  &lt;ThemeProvider theme={{ color: { accent: \"#dc2626\" } }}&gt;\n    &lt;p&gt;Nested theme overrides the accent color while inheriting spacing.&lt;/p&gt;\n  &lt;/ThemeProvider&gt;\n&lt;/ThemeProvider&gt;</code></pre>\n\n<h2>Keyboard Interactions</h2>\n\n<ul>\n<li>None -- presentational wrapper; interactive children handle their own keyboard interactions</li>\n</ul>\n\n<h2>ARIA</h2>\n\n<ul>\n<li>None -- presentational wrapper. Ensure sufficient color contrast in custom themes to maintain WCAG 2.2 AAA compliance.</li>\n</ul>\n\n<h2>When to Use</h2>\n\n<ul>\n<li>Use to scope visual themes to sections of a page</li>\n<li>Use to provide light and dark mode variants within the same page</li>\n<li>Use to allow nested theme overrides for specific content areas</li>\n<li>Use when different sections of a page require different visual styling</li>\n</ul>\n\n<h2>When Not to Use</h2>\n\n<ul>\n<li>Do not use for global app theming -- set CSS custom properties on <code>:root</code> instead</li>\n<li>Do not use when only a single style property needs to change -- use inline styles directly</li>\n<li>Do not use for layout concerns -- ThemeProvider is purely for visual theming</li>\n</ul>\n\n<h2>Headless</h2>\n\n<p>This component provides a <code>&lt;div&gt;</code> element with <code>display: contents</code> that applies CSS custom properties from a theme object, with zero visual styling. The consumer is responsible for referencing the <code>--theme-*</code> custom properties in their CSS and ensuring all themed content uses these properties consistently.</p>\n\n<h2>Styles</h2>\n\n<p>The consumer provides all CSS styling. The component renders with a <code>.theme-provider</code> class for targeting. No default styles are included -- this is a fully headless component. The component sets <code>display: contents</code> to avoid affecting layout.</p>\n\n<h2>Testing</h2>\n\n<ul>\n<li>Verify the component renders a <code>&lt;div&gt;</code> element with class <code>theme-provider</code></li>\n<li>Verify nested theme object is flattened into <code>--theme-*</code> CSS custom properties</li>\n<li>Verify base theme values are applied when no custom override is provided</li>\n<li>Verify nested ThemeProvider overrides parent theme values</li>\n<li>Verify <code>display: contents</code> is applied</li>\n<li>Verify pass-through attributes are applied</li>\n</ul>\n\n<h2>Advice</h2>\n\n<ul>\n<li><strong>Designers</strong>: Ensure all theme color combinations meet WCAG 2.2 AAA contrast ratios. Define a complete theme object so that no component is left unstyled. Test themes at multiple viewport sizes.</li>\n<li><strong>Developers</strong>: Use consistent naming conventions in theme objects. Always provide a base theme to ensure all custom properties have fallback values. Use CSS <code>var()</code> with fallbacks when referencing theme properties.</li>\n</ul>\n\n<h2>Related components</h2>\n\n<ul>\n<li><code>theme-picker</code> — a picker for selecting a visual theme</li>\n<li><code>theme-select</code> — a select dropdown for choosing a theme</li>\n<li><code>theme-view</code> — a read-only display of the current theme</li>\n</ul>\n\n<h2>References</h2>\n\n<ul>\n<li><a href=\"https://github.com/reuters-graphics/graphics-components\">Reuters Graphics Theme component</a></li>\n<li><a href=\"https://developer.mozilla.org/en-US/docs/Web/CSS/Using_CSS_custom_properties\">CSS Custom Properties (MDN)</a></li>\n</ul>";
  // BEGIN auto-generated component example consts
  const demoHtml: string = "<div class=\"theme-provider\" aria-label=\"a container that applies CSS custom properties from a theme object to its children\">ThemeProvider</div>";
  const svelteSource: string = "// In your Svelte component:\nimport ThemeProvider from \"lily-design-system-svelte-headless/components/ThemeProvider/ThemeProvider.svelte\";\n\n<ThemeProvider>\n  <!-- content -->\n</ThemeProvider>\n";
  // END auto-generated component example consts
</script>

